sql:
SELECT sport_name
  FROM sports
  WHERE popularity = (SELECT MAX(popularity) FROM sports);

SELECT MAX(stake_value) AS max_stake
FROM stakes
WHERE user_id = 1;

SELECT sport_name
FROM sports
WHERE sport_id = 0;

SELECT user_id
FROM reviews
WHERE rating = (SELECT MAX(rating) FROM reviews);

SELECT AVG(payout_value) AS average_payout
FROM payouts
WHERE match_id = 1;

