sql:
SELECT stake_value, created_at
FROM stakes
WHERE stake_id = 1;

SELECT sport_name, popularity
FROM sports
ORDER BY popularity DESC;

SELECT bookmaker_name, rating
FROM bookmakers
ORDER BY rating DESC;

SELECT odd_value
FROM odds
WHERE match_id = 1 AND bookmaker_id = 0;
